const express = require('express');
const router = express.Router();
const axios = require('axios');
const paypal = require('../config/paypalConfig');
require('dotenv').config();

// ── Pages ──
router.get('/', (req, res) => res.sendFile('index.html', { root: 'public' }));

// Keep EJS views for any sub-pages you add later
router.get('/about', (req, res) => res.render('about'));
router.get('/services', (req, res) => res.render('services'));
router.get('/contact', (req, res) => res.render('contact'));
router.get('/service-details', (req, res) => {
  const service = req.query.service || 'our service';
  res.render('service-details', { service });
});

// ── Contact Form ──
router.post('/submit-contact', (req, res) => {
  const { name, email, service, budget, message } = req.body;
  // TODO: wire up an email sender (e.g. nodemailer + Gmail or SendGrid)
  console.log('[Contact]', { name, email, service, budget, message });
  res.json({ ok: true });
});

// ── PayPal Payment ──
router.get('/pay', (req, res) => {
  const product = req.query.product || 'Digital Product';
  const amount  = parseFloat(req.query.amount) || 300;

  const create_payment_json = {
    intent: 'sale',
    payer:  { payment_method: 'paypal' },
    redirect_urls: {
      return_url: `${process.env.BASE_URL || 'http://localhost:3000'}/success`,
      cancel_url:  `${process.env.BASE_URL || 'http://localhost:3000'}/cancel`,
    },
    transactions: [{
      item_list: {
        items: [{ name: product, sku: '001', price: amount.toFixed(2), currency: 'USD', quantity: 1 }],
      },
      amount:      { total: amount.toFixed(2), currency: 'USD' },
      description: `Payment for ${product} — WFreelancers`,
    }],
  };

  paypal.payment.create(create_payment_json, (error, payment) => {
    if (error) {
      console.error('[PayPal Error]', error);
      return res.status(500).send('PayPal payment failed. Please try again.');
    }
    const approvalUrl = payment.links.find(l => l.rel === 'approval_url');
    if (approvalUrl) res.redirect(approvalUrl.href);
    else res.status(500).send('No PayPal approval URL returned.');
  });
});

router.get('/success', (req, res) => {
  res.send(`
    <html><body style="font-family:sans-serif;text-align:center;padding:4rem;background:#0a0a0a;color:#fafaf8">
      <h1 style="color:#c8f04a">✅ Payment successful!</h1>
      <p>Thank you for your purchase. Check your email for your download link.</p>
      <p>Questions? <a href="mailto:wfreelancers1@gmail.com" style="color:#c8f04a">wfreelancers1@gmail.com</a></p>
      <a href="/" style="display:inline-block;margin-top:2rem;background:#c8f04a;color:#000;padding:.75rem 2rem;border-radius:100px;text-decoration:none;font-weight:600">Back to store</a>
    </body></html>
  `);
});

router.get('/cancel', (req, res) => {
  res.redirect('/#store');
});

// ── M-Pesa STK Push ──
async function getMpesaToken() {
  const auth = Buffer.from(
    `${process.env.MPESA_CONSUMER_KEY}:${process.env.MPESA_CONSUMER_SECRET}`
  ).toString('base64');

  const { data } = await axios.get(
    'https://sandbox.safaricom.co.ke/oauth/v1/generate?grant_type=client_credentials',
    { headers: { Authorization: `Basic ${auth}` } }
  );
  return data.access_token;
}

router.post('/mpesa-pay', async (req, res) => {
  try {
    const { phone, amount, product } = req.body;
    const token = await getMpesaToken();

    // Correct YYYYMMDDHHmmss timestamp
    const timestamp = new Date().toISOString().replace(/[^0-9]/g, '').slice(0, 14);
    const shortcode  = process.env.BUSINESS_SHORTCODE;
    const passkey    = process.env.PASSKEY;
    const password   = Buffer.from(`${shortcode}${passkey}${timestamp}`).toString('base64');

    const payload = {
      BusinessShortCode: shortcode,
      Password:          password,
      Timestamp:         timestamp,
      TransactionType:   'CustomerPayBillOnline',
      Amount:            Math.ceil(amount),         // M-Pesa requires integers
      PartyA:            phone,
      PartyB:            shortcode,
      PhoneNumber:       phone,
      CallBackURL:       `${process.env.BASE_URL}/mpesa-callback`, // set BASE_URL in .env
      AccountReference:  'WFREELANCERS',
      TransactionDesc:   product || 'Digital Product',
    };

    const { data } = await axios.post(
      'https://sandbox.safaricom.co.ke/mpesa/stkpush/v1/processrequest',
      payload,
      { headers: { Authorization: `Bearer ${token}` } }
    );
    res.json(data);
  } catch (err) {
    console.error('[M-Pesa Error]', err.response?.data || err.message);
    res.status(500).json({ error: 'M-Pesa request failed. Please try again.' });
  }
});

// M-Pesa callback (Safaricom posts payment result here)
router.post('/mpesa-callback', (req, res) => {
  console.log('[M-Pesa Callback]', JSON.stringify(req.body, null, 2));
  // TODO: validate payment, mark order as paid, send download email
  res.json({ ResultCode: 0, ResultDesc: 'Accepted' });
});

module.exports = router;
